# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

from flask import Flask, request
import pymysql

app = Flask(__name__)

@app.route('/query', methods=['GET'])
def query_mysql():
    # get parameters from http request
    params = request.args
    
    db = pymysql.connect("host", "username", "password", "database")
 
    cursor = db.cursor()
    
    sql = 'SELECT * FROM table'  # base SQL query
  
    if params:  # dynamic part, if there are parameters in the request
        where_clauses = []
        
        for key, value in params.items():
            where_clause = f"{key}='{value}'"
            
            # string concatenation for SQL query construction
            sql += " WHERE " if not where_clauses else " AND " 
              
            where_clauses.append(where_clause)
        
        sql += ' AND '.join(where_clauses)
  
    try:
        cursor.execute(sql)
        results = cursor.fetchall()
      
        return {'results': str(results)}  # return the result as json
    
    except Exception as e:
        return {"error": str(e)}  # in case of any error, return it as json

if __name__ == '__main__':
    app.run(debug=True)